 63	//------------------------------------------------------------------------------
 64	struct rrc_eNB_ue_context_s *
 65	rrc_eNB_allocate_new_UE_context(
 66	  eNB_RRC_INST *rrc_instance_pP
 67	)
 68	//------------------------------------------------------------------------------
 69	{
 70	  struct rrc_eNB_ue_context_s *new_p;
 71	  new_p = (struct rrc_eNB_ue_context_s * )malloc(sizeof(struct rrc_eNB_ue_context_s));
 72	
 73	  if (new_p == NULL) {
 74	    LOG_E(RRC, "Cannot allocate new ue context\n");
 75	    return NULL;
 76	  }
 77	
 78	  memset(new_p, 0, sizeof(struct rrc_eNB_ue_context_s));
 79	  new_p->local_uid = uid_linear_allocator_new(&rrc_instance_pP->uid_allocator);
 80	
 81	  for(int i = 0; i < NB_RB_MAX; i++) {
 82	    new_p->ue_context.e_rab[i].xid = -1;
 83	    new_p->ue_context.modify_e_rab[i].xid = -1;
 84	  }
 85	
 86	  return new_p;
 87	}
