 90	//------------------------------------------------------------------------------
 91	struct rrc_eNB_ue_context_s *
 92	rrc_eNB_get_ue_context(
 93	  eNB_RRC_INST *rrc_instance_pP,
 94	  rnti_t rntiP)
 95	//------------------------------------------------------------------------------
 96	{
 97	  rrc_eNB_ue_context_t temp;
 98	  memset(&temp, 0, sizeof(struct rrc_eNB_ue_context_s));
 99	  /* eNB ue rrc id = 24 bits wide */
100	  temp.ue_id_rnti = rntiP;
101	  struct rrc_eNB_ue_context_s   *ue_context_p = NULL;
102	  ue_context_p = RB_FIND(rrc_ue_tree_s, &rrc_instance_pP->rrc_ue_head, &temp);
103	
104	  if ( ue_context_p != NULL) {
105	    return ue_context_p;
106	  } else {
107	    RB_FOREACH(ue_context_p, rrc_ue_tree_s, &(rrc_instance_pP->rrc_ue_head)) {
108	      if (ue_context_p->ue_context.rnti == rntiP) {
109	        return ue_context_p;
110	      }
111	    }
112	    return NULL;
113	  }
114	}
