134	//------------------------------------------------------------------------------
135	void rrc_eNB_remove_ue_context(
136	  const protocol_ctxt_t *const ctxt_pP,
137	  eNB_RRC_INST                *rrc_instance_pP,
138	  struct rrc_eNB_ue_context_s *ue_context_pP)
139	//------------------------------------------------------------------------------
140	{
141	  if (rrc_instance_pP == NULL) {
142	    LOG_E(RRC, PROTOCOL_RRC_CTXT_UE_FMT" Bad RRC instance\n",
143	          PROTOCOL_RRC_CTXT_UE_ARGS(ctxt_pP));
144	    return;
145	  }
146	
147	  if (ue_context_pP == NULL) {
148	    LOG_E(RRC, PROTOCOL_RRC_CTXT_UE_FMT" Trying to free a NULL UE context\n",
149	          PROTOCOL_RRC_CTXT_UE_ARGS(ctxt_pP));
150	    return;
151	  }
152	
153	  RB_REMOVE(rrc_ue_tree_s, &rrc_instance_pP->rrc_ue_head, ue_context_pP);
154	  rrc_eNB_free_mem_UE_context(ctxt_pP, ue_context_pP);
155	  uid_linear_allocator_free(&rrc_instance_pP->uid_allocator, ue_context_pP->local_uid);
156	  free(ue_context_pP);
157	  rrc_instance_pP->Nb_ue --;
158	  LOG_I(RRC,
159	        PROTOCOL_RRC_CTXT_UE_FMT" Removed UE context\n",
160	        PROTOCOL_RRC_CTXT_UE_ARGS(ctxt_pP));
161	}
